
import React, { useState } from 'react'
import { View, Text } from 'react-native'
import {NavigationContainer} from '@react-navigation/native'
import {createStackNavigator} from '@react-navigation/stack'
import { ScrollView, TouchableOpacity, TextInput } from 'react-native-gesture-handler'

const Stack = createStackNavigator()

export default function App(){
    return(
        <NavigationContainer>
            <Stack.Navigator headerMode='none'>
                <Stack.Screen 
                    name = 'SignUp'
                    component = {SignUp} 
                ></Stack.Screen>
            </Stack.Navigator>
        </NavigationContainer>
    )
}

const signUpMethod = 
`未注册只能浏览推荐内容
不能搜索、提问、回答
注册方式: 指数式增长
首先数据库中有3位原始用户
当新用户想要注册时, 提供以下信息
    1. 职业: [老师,学生]
    2. 等级: [小学,初中,... 博士]
    3. 学校: 自由填写或从列表搜索 
    4. 姓名
    5. 邮箱(最好是.edu), 密码
然后从已有用户中搜索3位认识的人
请求他们辅助认证`
const jobs = [0,'老师',0,'学生',0]
const levels = ['小学','初中','高中','本科','研究生','博士']
const actions = ['忘记密码',0,'注册/登录']

function SignUp(){
    const [form,setForm] = useState({
        job:'',level:'',school:'',name:'',
        email:'',password:'',
        helpers:[],helperQuery:'',
    })
    function set(object){
        setForm(Object.assign({...form},object)) 
    }
    return(
        <Body>
        <ScrollView>
            <Text>{JSON.stringify(form)}</Text>
            <Scroll>
                <Txt>{signUpMethod}</Txt>
            </Scroll>
            <Btns onPick={job=>set({job})}>{jobs}</Btns>
            <Btns onPick={level=>set({level})}>{levels}</Btns>
            <Input p={'您的学校'} 
                on={school=>set({school})}></Input>
            <Input p={'您的真实姓名'} 
                on={name=>set({name})}></Input>
            <Input p={'您的邮箱 (最好是.edu)'} 
                on={email=>set({email})}></Input>
            <Input p={'设置您的密码'} 
                on={password=>set({password})}></Input>
            <Input p={'搜索用户帮您认证(学校+姓名)'} 
                on={helperQuery=>set({helperQuery})}></Input>
            <Btns onPick={action=>alert(action)}>{actions}</Btns>
        </ScrollView>
        </Body>
    )
}

const Body = ({children,w})=>
    <View style={{
        flex:1,justifyContent:'center',
        backgroundColor:'white',width:w,alignSelf:'center',
    }}>{children}</View>

const Row = ({children})=>
    <View style={{flexDirection:'row',flexWrap:'wrap',
        justifyContent:'center', margin:10}}>
        {children}
    </View>

const Box = ({children,h=120})=>
    <View style={{borderRadius:30,elevation:6,
        backgroundColor:'white',height:h,
        paddingHorizontal:20, paddingVertical:10,
        margin:10}}>
        {children}
    </View>

const Scroll = ({children})=>
    <Box>
        <ScrollView >
            {children}
        </ScrollView>
    </Box>

const Txt = ({children,c='grey'})=>
    <Text style={{
        color:c,fontSize:18,fontWeight:'bold',

    }}>{children}</Text>

const Input = ({children,p,on,c='grey'})=>
    <TextInput placeholder={p} style={{
        color:c,fontSize:18,fontWeight:'bold',
        textAlign:'center',borderRadius:30,elevation:6,
        backgroundColor:'white',
        paddingHorizontal:20, paddingVertical:10,
        margin:10,
    }} onChangeText={text=>on(text)}>{children}</TextInput>

const Btn = ({children,on,b='black'})=>
    <TouchableOpacity style={{
        backgroundColor:b, borderRadius:30,
        paddingHorizontal:10,paddingVertical:6,
        marginHorizontal:6,marginVertical:3,
        minWidth:60, alignItems:'center',
    }} onPress={on}>
        <Txt c='white'>{children}</Txt>
    </TouchableOpacity>

function Btns({children,onPick}){
    const [picked,setPicked] = useState()
    function on(item){ setPicked(item); onPick(item) }
    return(
        <Row>
            {children.map((item,index)=>
                item? <Btn key={index} on={()=>on(item)}
                b={picked==item?'red':undefined}>
                {item}</Btn> : <Dummy key={index}/>
            )}
        </Row>
    )
}

const Dummy = ()=><View style={{flex:1}}></View>